import type { DMMF } from '@prisma/generator-helper'

/**
 * Maps a DMMF scalar field type to its TypeScript equivalent.
 *
 * Relation fields (kind === 'object') are excluded here; callers handle them
 * separately when they want to include or skip relation properties.
 */
export function scalarToTs(field: DMMF.Field): string {
  if (field.kind === 'enum') {
    return field.type
  }

  switch (field.type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    default:
      return 'unknown'
  }
}

/** Renders the TypeScript type for a field, including list and optional modifiers. */
export function fieldTsType(field: DMMF.Field): string {
  if (field.kind === 'object') {
    // Relation fields are typed as the related model (or an array thereof).
    const base = field.isList ? `${field.type}[]` : field.type
    return field.isRequired ? base : `${base} | null`
  }

  const base = field.isList ? `${scalarToTs(field)}[]` : scalarToTs(field)
  return field.isRequired ? base : `${base} | null`
}

/** Renders a single field line inside a TypeScript interface. */
export function renderInterfaceField(field: DMMF.Field): string {
  const optional = !field.isRequired ? '?' : ''
  const type = field.isList ? `${scalarToTs(field)}[]` : scalarToTs(field)

  if (field.kind === 'object') {
    // Omit relation fields from the plain model interface; they belong in a
    // separate "with-relations" variant that callers can opt into.
    return ''
  }

  return `  ${field.name}${optional}: ${type}`
}

/** Renders a full TypeScript interface for one DMMF model. */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .map(renderInterfaceField)
    .filter((line) => line !== '')
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/** Renders the `CreateInput` type for a model (all required fields mandatory, optional ones… optional). */
export function renderCreateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated)
    .map((f) => {
      const hasAutoDefault =
        f.hasDefaultValue ||
        f.isUpdatedAt ||
        (f.isId && f.hasDefaultValue !== false && f.default !== undefined)
      const optional = !f.isRequired || hasAutoDefault ? '?' : ''
      const base = f.isList ? `${scalarToTs(f)}[]` : scalarToTs(f)
      const type = f.isRequired && !hasAutoDefault ? base : `${base} | null`
      return `  ${f.name}${optional}: ${type}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

/** Renders the `UpdateInput` type for a model (all fields optional). */
export function renderUpdateInput(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated)
    .map((f) => {
      const base = f.isList ? `${scalarToTs(f)}[]` : scalarToTs(f)
