import fs from 'node:fs/promises'
import path from 'node:path'

import type { GeneratorOptions } from '@prisma/generator-helper'

import { renderFile } from './template'

/**
 * Runs the REST client generation step.
 *
 * Reads the DMMF document from `options.dmmf`, generates a single
 * `rest-client.ts` file containing typed interfaces and a `PrismaRestClient`
 * class, and writes it to the resolved output directory.
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options)
  const { datamodel } = options.dmmf

  const content = renderFile(datamodel.models, datamodel.enums)

  await fs.mkdir(outputDir, { recursive: true })
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

/**
 * Resolves the output directory for the generated file.
 *
 * Falls back to `./generated/rest-client` relative to the schema file when
 * no explicit `output` is set in the generator config.
 */
function resolveOutputDir(options: GeneratorOptions): string {
  const outputValue = options.generator.output?.value
  if (outputValue) {
    return path.isAbsolute(outputValue) ? outputValue : path.resolve(outputValue)
  }
  return path.resolve(path.dirname(options.schemaPath), 'generated', 'rest-client')
}

