    '    }',
    '    return res.json() as Promise<T>',
    '  }',
    '',
    '  /** Extracts the first defined value from a WhereUniqueInput object. */',
    '  #extractId(where: Record<string, unknown>): string | number {',
    '    const value = Object.values(where).find((v) => v !== undefined)',
    '    if (value === undefined) {',
    '      throw new Error(\'WhereUniqueInput must contain at least one field\')',
    '    }',
    '    return value as string | number',
    '  }',
    allMethods,
    '}',
    '',
  )

  return sections.join('\n')
}
